class LoginVM extends AsyncNotifier<void> {
  @override Future<void> build() async {}

  Future<void> signIn(String email, String pwd) async {
    state = const AsyncLoading();
    state = await AsyncValue.guard(() => ref.read(authRepoProvider).signIn(email, pwd));
  }
