final loginVMProvider = AsyncNotifierProvider<LoginVM, void>(LoginVM.new);

class LoginPage extends ConsumerWidget {
  const LoginPage({super.key});
  @override Widget build(_, ref) {
    ref.listen(loginVMProvider, (_, next) {
      next.whenOrNull(
        data: (_) => ref.read(routerProvider).go('/home'),
        error: (e, _) => /* show snack */ {},
      );
    });
    final loading = ref.watch(loginVMProvider).isLoading;
    return LoginForm(loading: loading,
