// ── MVI / BLoC — single state, unidirectional ──
sealed class LoginEvent {}
final class Submitted extends LoginEvent { final String email, pwd; Submitted(this.email, this.pwd); }

sealed class LoginState {}
final class Idle    extends LoginState { const Idle(); }
final class Loading extends LoginState { const Loading(); }
final class Done    extends LoginState { const Done(); }
final class Failed  extends LoginState { final Object error; Failed(this.error); }

class LoginBloc extends Bloc<LoginEvent, LoginState> {
  LoginBloc(this.repo) : super(const Idle()) {
    on<Submitted>((e, emit) async {
      emit(const Loading());
      try { await repo.signIn(e.email, e.pwd); emit(const Done()); }
      catch (err) { emit(Failed(err)); }
    });
  }
  final AuthRepository repo;
}
// View dispatches Submitted; renders state. Pure unidirectional flow.

