// ── Domain — pure ──
class User {
  final int id;
  final String fullName;
  final String? email;
  final bool active;

  const User({
    required this.id,
    required this.fullName,
    this.email,
    required this.active,
  });

  @override bool operator ==(Object other) =>
      other is User && other.id == id && other.fullName == fullName &&
      other.email == email && other.active == active;
  @override int get hashCode => Object.hash(id, fullName, email, active);
}

// ── Data DTO — wire format ──
class UserDto {
  final int id;
  final String firstName;
  final String lastName;
  final String? emailAddress;
  final String status;          // 'active' | 'suspended'

  const UserDto({
    required this.id, required this.firstName, required this.lastName,
    this.emailAddress, required this.status,
  });

  factory UserDto.fromJson(Map<String, dynamic> j) => UserDto(
    id: j['id'] as int,
    firstName: j['first_name'] as String,
    lastName: j['last_name'] as String,
    emailAddress: j['email_address'] as String?,
    status: j['status'] as String,
  );

  Map<String, dynamic> toJson() => {
    'id': id,
    'first_name': firstName,
    'last_name': lastName,
    if (emailAddress != null) 'email_address': emailAddress,
    'status': status,
  };
}

// ── Mapper — single source of truth for the conversion ──
extension UserDtoX on UserDto {
  User toEntity() => User(
    id: id,
    fullName: '$firstName $lastName'.trim(),
    email: emailAddress,
    active: status == 'active',
  );
}

extension UserX on User {
  UserDto toDto({String? originalFirst, String? originalLast}) {
    final parts = fullName.split(' ');
    return UserDto(
      id: id,
      firstName: originalFirst ?? (parts.isNotEmpty ? parts.first : ''),
      lastName:  originalLast  ?? (parts.length > 1 ? parts.sublist(1).join(' ') : ''),
      emailAddress: email,
      status: active ? 'active' : 'suspended',
    );
  }
}

